/**
 * Weight bracket classifier for parcel shipping.
 *
 * Brackets:
 *   standard : 0 < weight < 10 kg
 *   heavy    : 10 <= weight < 50 kg
 *   freight  : 50 <= weight <= 1000 kg
 *
 * Throws a validation error for weight <= 0 or weight > 1000.
 */
export type WeightBracket = "standard" | "heavy" | "freight";

export class WeightValidationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "WeightValidationError";
  }
}

export function classifyWeight(weightKg: number): WeightBracket {
  if (weightKg <= 0) {
    throw new WeightValidationError(
      `Invalid weight: ${weightKg} kg. Weight must be greater than 0.`
    );
  }
  if (weightKg > 1000) {
    throw new WeightValidationError(
      `Invalid weight: ${weightKg} kg. Weight must not exceed 1000 kg.`
    );
  }

  if (weightKg < 10) {
    return "standard";
  }
  if (weightKg < 50) {
    return "heavy";
  }
  return "freight";
}

